import { readFileSync, readdirSync, existsSync } from "node:fs";
import assert from "node:assert/strict";

const final = readFileSync("FINAL.md", "utf8");
assert.match(final, /AMBER-FOX/);
const files = readdirSync("src/batch").filter((f) => /^f\d{2}\.js$/.test(f));
assert.equal(files.length, 20, `expected 20 batch files, got ${files.length}`);
for (const f of files) {
  const body = readFileSync(`src/batch/${f}`, "utf8");
  const id = f.replace(".js", "");
  assert.match(body, new RegExp(`id\\s*=\\s*["']${id}["']`));
}
const scratch = existsSync(".reaper/memory/scratch.md")
  ? readFileSync(".reaper/memory/scratch.md", "utf8")
  : "";
assert.match(scratch, /AMBER-FOX/);
console.log("ok", files.length);
